// 取得上一個 Python 節點吐出來的文字 (假設放在 stdout 欄位)
let text = $input.first().json.stdout ;

// 使用 JavaScript 把 * 和 # 替換成空字串
let cleanText = text.replace(/[*#_><]/g, '');

// 把乾淨的文字輸出給下一個節點
return {
  json: {
    clean_summary: cleanText
  }
};

// 1. 確保抓到你輸入的 clean_summary
const text = $input.first().json.clean_summary || "";

// 2. 準確框出 [關鍵字]： 到 3. [發生時間]： 中間的所有內容
// 使用 \s* 容忍任何數量的空白與換行
const match = text.match(/\[關鍵字\]：([\s\S]*?)3\.\s*\[發生時間\]/);

let extractedKeywords = "";

if (match && match[1]) {
    // 3. 把抓出來的內容，變成完美的逗號分隔字串
    extractedKeywords = match[1]
        .split('\n')                  // 步驟A：遇到換行就切開，變成陣列
        .map(word => word.trim())     // 步驟B：把每個字頭尾的「空白」跟「縮排」都砍掉
        .filter(word => word !== "")  // 步驟C：把切出來的「空字串」過濾掉
        .join(',');                   // 步驟D：剩下的乾淨關鍵字，用逗號接起來
}

return {
    keywords: extractedKeywords
};

