                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ summary: summaryText })
                });

                if (response.ok) {
                    alert(' Successfully triggered the Dispatcher system!');
                    btn.innerHTML = '✨Dispatch Complete';
