// 取得原始文字
let text = $input.first().json.body.summary || "";

// 1. 先把原本可能存在的 \r\n 統一轉成 \n
const regex = /(\d\.\s\[[^\]]+\])/g;

// 在匹配到的標籤前面加上兩個換行符號 \n\n
let formatted = text.replace(regex, '\n\n$1').trim();
formatted = formatted.replace(/(\[[^\]]+\]：)\s?/g, '$1\n    ');
formatted = formatted.replace(/\s-\s/g, '\n    - ');

return {
  formattedText: formatted
};
